import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { useParams, useNavigate } from "react-router-dom";

function ProductDetails()
{

    const navigate = useNavigate();
    const { category, product } = useParams();
    const [loading, setLoading] = useState(true);
    const [currentProduct, setProduct] = useState({});
    const [currentCategory, setCategory] = useState({});

    useEffect(() =>
    {
        let isMounted = true;

        axios.get(`/api/fetchProducts/${category}/${product}`).then(res =>
        {
            if (isMounted)
            {
                if (res.data.status === 200)
                {
                    setProduct(res.data.product);
                    setCategory(res.data.category);
                    setLoading(false);
                }
                else if (res.data.status === 404)
                {
                    // Use navigate for redirection
                    navigate('/collections');
                    Swal.fire("Warning", res.data.message, "error");
                }
            }
        });

        return () =>
        {
            isMounted = false;
        };
    }, [category, product, navigate]);


    if(loading)
    {
        return <h4>Loading Product Details...</h4>
    }
    else
    {
        var avail_stock = '';
        if(currentProduct.qty > 0)
        {
            avail_stock = <div>
                <label className="btn-sm btn-success px-4 mt-2">In stock</label>
                <div className="row">
                    <div className="col-md-3 mt-3">
                        <div className="input-group">
                            <button type="button" className="input-group-text">-</button>
                            <div className="form-control text-center">1</div>
                            <button type="button" className="input-group-text">+</button>
                        </div>
                    </div>
                    <div className="col-md-3 mt-3">
                        <button type="button" className="btn btn-primary w-100">Add to Cart</button>
                    </div>
                </div>
            </div>
        }
        else
        {
            avail_stock = <div>
                <label className="btn-sm btn-danger px-4 mt-2">Out of stock</label>
            </div>
        }
    }

    return (
        <div>
            <div className="py-3 bg-warning">
                <div className="container">
                    <h6>Collections / {currentCategory.name} / {currentProduct.name}</h6>
                </div>
            </div>

            <div className="py-3">
                <div className="container">
                    <div className="row">
                        <div className="col-md-4 border-end">
                            <img src={`http://localhost:8000/${currentProduct.image}`} alt={currentProduct.name} className="w-100" />
                        </div>

                        <div className="col-md-8">
                            <h4>
                                {currentProduct.name}
                                <span className="float-end badge btn-sm btn-danger badge-pil"> {currentProduct.brand} </span>
                            </h4>
                            <p> {currentProduct.description} </p>
                            <h4 className="mb-1">
                                Rs: {currentProduct.selling_price}
                                <s className="ms-2"> Rs: {currentProduct.original_price} </s>
                            </h4>
                            <div>
                                {avail_stock}
                            </div>
                        </div>

                    </div>
                </div>
            </div>
        </div>
    )
}

export default ProductDetails;
